try {
  let response = $input.item.json.message.content;
  if (typeof response === 'string') {
    response = response.replace(/^```json/g, '').replace(/```$/g, '').trim();
    response = JSON.parse(response);
  }
  const agent = (response.agent === 'job_ad_creator') ? 'job_ad_creator' : 'job_description_generator';
  const confidence = (typeof response.confidence === 'number') ? response.confidence : 0.5;
  return { json: { agent: agent, confidence: confidence } };
} catch (e) {
  return { json: { agent: 'job_description_generator', confidence: 0.1, error: 'Failed to parse LLM intent' } };
}
